--
-- Table structure for table `ai_assignment_candidates`
--

DROP TABLE IF EXISTS `ai_assignment_candidates`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `ai_assignment_candidates` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `venue_id` int(11) NOT NULL,
  `assignment_log_id` int(11) NOT NULL,
  `booking_id` int(11) NOT NULL,
  `candidate_rank` int(11) NOT NULL,
  `area_id` int(11) DEFAULT NULL,
  `table_ids_json` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NOT NULL CHECK (json_valid(`table_ids_json`)),
  `table_numbers_json` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NOT NULL CHECK (json_valid(`table_numbers_json`)),
  `capacity` int(11) NOT NULL,
  `score` decimal(10,2) NOT NULL,
  `selected` tinyint(1) NOT NULL DEFAULT 0,
  `feature_snapshot_json` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NOT NULL CHECK (json_valid(`feature_snapshot_json`)),
  `created_at` datetime NOT NULL,
