--
-- Table structure for table `ai_assignment_logs`
--

DROP TABLE IF EXISTS `ai_assignment_logs`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `ai_assignment_logs` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `venue_id` int(11) NOT NULL,
  `booking_id` int(11) NOT NULL,
  `suggested_area_id` int(11) DEFAULT NULL,
  `suggested_table_numbers_json` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NOT NULL CHECK (json_valid(`suggested_table_numbers_json`)),
  `explanation` text NOT NULL,
  `rules_snapshot_json` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NOT NULL CHECK (json_valid(`rules_snapshot_json`)),
  `accepted_by_user_id` int(11) DEFAULT NULL,
  `accepted_at` datetime DEFAULT NULL,
  `final_table_numbers_json` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NOT NULL CHECK (json_valid(`final_table_numbers_json`)),
  `overridden` tinyint(1) NOT NULL DEFAULT 0,
  `created_at` datetime NOT NULL,
  PRIMARY KEY (`id`),
  KEY `fk_ai_booking` (`booking_id`),
  KEY `fk_ai_area` (`suggested_area_id`),
  KEY `fk_ai_user` (`accepted_by_user_id`),
  CONSTRAINT `fk_ai_area` FOREIGN KEY (`suggested_area_id`) REFERENCES `areas` (`id`),
  CONSTRAINT `fk_ai_booking` FOREIGN KEY (`booking_id`) REFERENCES `bookings` (`id`) ON DELETE CASCADE,
  CONSTRAINT `fk_ai_user` FOREIGN KEY (`accepted_by_user_id`) REFERENCES `users` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=40 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

